#define NP namespace
using NP std;
il ll read()
{
    ll x=0,f=1;char ch=gc();
    wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
    return x*f;
}
void write(ll x)
{
    if(x<0)pc('-'),x=-x;
    if(x>9)write(x/10);
    pc(x%10+'0');
}
void writeln(ll x)
{
    write(x);
    puts("");
    return;
}
CI MAXN=2e4+5,MOD=1e4;
ll f[2][MAXN],pr[2][MAXN],n,c;
bool p;
int main(void)
{
    cin>>n>>c;
    f[1][1]=1;
    for(int j=1;j<=c+1;j++)
        pr[1][j]=1;
    for(int i=2;i<=n;i++)
    {
        for(int j=1;j<=c+1;j++)
        {
            f[p][j]=(pr[!p][j]-pr[!p][max(j-i,0)]+MOD)%MOD;
            pr[p][j]=(pr[p][j-1]+f[p][j]+MOD)%MOD;
        }
        p=!p;
    }
    cout<<f[!p][c+1];
    return false;
}
